INSERT INTO public.photos VALUES (24162, 'Calle del Asalto 1931', 'Imagen capturada en la calle del Asalto durante el desarrollo del tradicional Ferial de Ganados que en ese entorno se celebraba con ocasiâ”œâ”‚n de las fiestas mayores de la localidad, en octubre. Este ferial tuvo dos ubicaciones: una primera, en el paseo de la Mina, entre los viveros del Ayuntamiento junto al puente de San Josâ”œآ® y la calle de Moret, y la de la imagen, en la calle del Asalto entre el Corral de Abastos de Intendencia y el convento de las Capuchinas. Allâ”œآ،, la compra y venta de caballerâ”œآ،as menores y mayores suponâ”œآ،a un importante trasiego de personas asâ”œآ، como el cambio de mano de muchos miles de duros. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.64926300, -0.87243500, '0101000020E610000025581CCEFCEAEBBF5DC0CB0C1BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36435520482.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36435520482.webp', 'https://www.flickr.com/photos/zaragozaantigua/36435520482/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24447, 'Fielato calle Asalto 1961', 'Archivo Municipal de Zaragoza. JARKE-JARIA. 22/VII/1961. "Inauguraciâ”œâ”‚n del fielato de la calle Asalto." "Fielato" era el nombre que recibâ”œآ،an las casetas de cobro de arbitrios y tasas municipales sobre trâ”œأ­fico de mercancâ”œآ،as ("fielato": fiel o balanza para calcular el peaje). Su nombre oficial era "Estaciâ”œâ”‚n Sanitaria" ya que, ademâ”œأ­s de su funciâ”œâ”‚n recaudatoria, controlaban el estado sanitario de los alimentos que entraban en la ciudad. En la imagen, "fielato" reciâ”œآ®n inaugurado en la calle Asalto, junto al Depâ”œâ”‚sito Corral de la Leâ”œâ–’a del Ejâ”œآ®rcito (a la derecha), y el nuevo puente sobre el râ”œآ،o Huerva que conectaba con las traseras del Cuartel de Intendencia de San Josâ”œآ® (a la izquierda). Por encima de los â”œأ­rboles, una de las chimeneas de la antigua fâ”œأ­brica de regaliz.', 1961, 1961, 1961, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.64917800, -0.87144900, '0101000020E61000008F386403E9E2EBBF2FA4C34318D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15181901888.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15181901888.webp', 'https://www.flickr.com/photos/zaragozaantigua/15181901888/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24454, 'Pl. de las Heras 1925', 'Los "grandes talleres mecâ”œأ­nicos de serrerâ”œآ،a y carpinterâ”œآ،a Manuel Soria Larios" estaban ubicados sobre un amplio solar de 1.500 m2 entre las calles de Alcalâ”œأ­, Manuela Sancho, y la plaza de las Eras. Surtâ”œآ،an de madera trabajada a obras de construcciâ”œâ”‚n, llegando a abastecer a notables proyectos de arquitectos como Julio Bravo Folch (ya fallecido), y Francisco Albiâ”œâ–’ana (serâ”œأ­ fusilado en Valdespartera 9 aâ”œâ–’os despuâ”œآ®s). En la imagen, aspecto del enorme edificio de dos plantas sede de los talleres. La captura ha sido realizada desde la plaza de las Heras. A la izquierda, se levantaba el inmediato convento de las MM. Capuchinas. Este goloso edificio llegâ”œâ”‚ intacto hasta finales de la dâ”œآ®cada de los aâ”œâ–’os 60 del pasado siglo, cuando fue piqueteado y sustituido por un compacto, macizo y anodino bloque de viviendas de ocho alturas de los del desarrollismo, de esos a los que les da igual estar en la plaza de las Eras, que en la calle del Doce de Octubre. Fuente visual: revista "La Esfera", setiembre 1925.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65001100, -0.87182500, '0101000020E6100000F5B9DA8AFDE5EBBF2785798F33D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17370283471.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17370283471.webp', 'https://www.flickr.com/photos/zaragozaantigua/17370283471/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24960, 'Parque Bruil. Oso Juan 1973', 'Desde su inauguraciâ”œâ”‚n en 1965 como espacio pâ”œâ•‘blico municipal, el Parque Bruil albergaba un pequeâ”œâ–’o أ”أ‡آ£zooأ”أ‡أک de animales irracionales como monos, pavos reales, y una pareja de osos, أ”أ‡آ£Juanأ”أ‡أک, el chico, y أ”أ‡آ£Nicolasaأ”أ‡أک, la chica. Sus condiciones vitales eran penosas. A partir de 1979, recuperada la democracia municipal, esta situaciâ”œâ”‚n empezâ”œâ”‚ a ser denunciada por personas y entidades. En 1984, finalmente, el Ayuntamiento desmantelâ”œâ”‚ el أ”أ‡آ£zooأ”أ‡أک, en el que ya sâ”œâ”‚lo quedaba la osa أ”أ‡آ£Nicolasaأ”أ‡أک, tuerta por la agresiâ”œâ”‚n de otro tipo de animales irracionales, indâ”œآ،genas bâ”œآ،pedos, en este caso. أ”أ‡آ£Juanأ”أ‡أک habâ”œآ،a muerto antes. En la imagen, el oso أ”أ‡آ£Juanأ”أ‡أک nos saluda a modo de despedida, desde la distancia en el espacio y el tiempo del triste encierro en su jaula, instalada en la zona del Parque mâ”œأ­s inmediata a la calle de Mariano Alvira Lasierra.', 1973, 1973, 1973, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.64936200, -0.87037600, '0101000020E61000003E25E7C41EDAEBBFF1A1444B1ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14836201384.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14836201384.webp', 'https://www.flickr.com/photos/zaragozaantigua/14836201384/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23984, 'Dâ”œآ،a de la Victoria 1963', 'Unos vehâ”œآ،culos preparados para el combate acuâ”œأ­tico desfilan en Zaragoza ante el Convento de Jerusalâ”œآ®n, sito en la confluencia de la calle homâ”œâ”‚nima con Isabel la Catâ”œâ”‚lica. Participan en la celebraciâ”œâ”‚n del "Desfile del Dâ”œآ،a de la Victoria", que desde 1940 se vino celebrando hasta 1976. â”œأ«ste de la foto, de 1963, fue el â”œâ•‘ltimo con esa denominaciâ”œâ”‚n, que desde 1964 pasâ”œâ”‚ a llamarse "Desfile de la Paz", por los 25 aâ”œâ–’os de pervivencia de la dictadura fascista. Hoy se sigue celebrando, con su enmascaramiento desde 1978 de "Dâ”œآ،a de las Fuerzas Armadas". Fuente: www.facebook.com/photo.php?fbid=10203727390279866&set...', 1963, 1963, 1963, 'Anos 60', 'UNIVERSIDAD', 41.63491700, -0.90192000, '0101000020E61000005C77F35487DCECBF5456D3F544D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15437715505.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15437715505.webp', 'https://www.flickr.com/photos/zaragozaantigua/15437715505/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24965, 'Torre de Bruil c.1959', 'La antigua huerta del convento de San Agustâ”œآ،n, tras su desamortizaciâ”œâ”‚n a mediados del siglo XIX, pasâ”œâ”‚ a propiedad del industrial Juan Bruil, que la convirtiâ”œâ”‚ en torre de recreo con extensa zona verde visitable. Abandonada desde finales del XIX, el Ayuntamiento iniciâ”œâ”‚ gestiones en 1953 para convertirla en parque, incluyendo el molino de aceite de la ciudad. En 1959 consiguiâ”œâ”‚ expropiarla, cuando la finca era propiedad de Josâ”œآ® Marâ”œآ،a Monserrat y ofrecâ”œآ،a este aspecto como depâ”œâ”‚sito de chatarra rodante, tal vez como recuerdo de los aâ”œâ–’os en que fue utilizada para acoger al parque automovilâ”œآ،stico. A pesar del tiempo transcurrido, esta torre y su entorno seguâ”œآ،an siendo denominados de Bruil, nombre que se dio al parque inaugurado aâ”œâ–’os despuâ”œآ®s. Al fondo de la imagen, tras los â”œأ­rboles, la calle del Asalto. Fuente visual: Gerardo Sancho Ramo, en AMZ.', 1959, 1959, 1959, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.64967600, -0.86985900, '0101000020E61000005133A48AE2D5EBBF807F4A9528D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15006624873.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15006624873.webp', 'https://www.flickr.com/photos/zaragozaantigua/15006624873/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24980, 'Calle Asalto 1974', 'Imagen no muy afortunada de calidad, aunque interesante por la insâ”œâ”‚lita y despejada visual que desde el parque de Bruil (en obras de remodelaciâ”œâ”‚n) habâ”œآ،a del antiguo convento barroco de las MM. Agustinas de Santa Mâ”œâ”‚nica, cuya brumosa silueta queda difuminada al fondo. Destaca el remate de su fachada principal, en la esquina de la calle Palomar y Manuela Sancho, y de su octogonal câ”œâ•‘pula, e incluso puede apreciarse, por encima, câ”œâ”‚mo emerge desmochada la torre del convento de San Agustâ”œآ،n. A su izquierda, el acentuado desemboque de la calle de Cantâ”œآ،n y Gamboa en la calle Asalto. Fuente visual: Archivo Pâ”œâ•‘blico Municipal, Gerardo Sancho Ramo.', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65022200, -0.87008500, '0101000020E610000064AF777FBCD7EBBFE29178793AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23584671634.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23584671634.webp', 'https://www.flickr.com/photos/zaragozaantigua/23584671634/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24987, 'Calle Asalto 1974', 'Antiguo molino de aceite de Goicoechea en su original ubicaciâ”œâ”‚n que confrontaba con el molino de aceite de la ciudad, y cuyos restos fueron incorporados como decoraciâ”œâ”‚n del parque Bruil, aunque sin râ”œâ”‚tulo informativo alguno. Al fondo, desemboque de la calle de Cantâ”œآ،n y Gamboa en la del Asalto, y a la derecha, irrepetible vista del barroco convento de Santa Mâ”œâ”‚nica de las Madres Agustinas, y de la desmochada torre del convento de San Agustâ”œآ،n.', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.64958900, -0.87033200, '0101000020E61000005531957EC2D9EBBFB16B7BBB25D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33218893031.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33218893031.webp', 'https://www.flickr.com/photos/zaragozaantigua/33218893031/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24988, 'Parque Bruil 1972', 'Imagen de la pareja de osos enjaulada para supuesto disfrute del pâ”œâ•‘blico, a los que se puso los nombres de Nicolasa (izquierda) y Juan (derecha), en un tiempo en la que la antigua torre de Bruil ejercâ”œآ،a de zona verde, parque de juegos infantiles, piscina, y zoolâ”œâ”‚gico, e incluso habâ”œآ،a sugerencias para aâ”œâ–’adirle la funciâ”œâ”‚n de jardâ”œآ،n botâ”œأ­nico. Tanta acumulaciâ”œâ”‚n de funciones, por el mismo precio, trajo poca fortuna a este espacio, sobre todo a los animales en â”œآ®l prisioneros, como Juan y Nicolasa, a los que se arrastrâ”œâ”‚ a una existencia bien poco edificante, que terminaron muy malamente. Fuente visual: Heraldo de Aragâ”œâ”‚n.', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.64958900, -0.87033200, '0101000020E61000005531957EC2D9EBBFB16B7BBB25D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34364011013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34364011013.webp', 'https://www.flickr.com/photos/zaragozaantigua/34364011013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25801, 'Calle Asalto 1975', 'Imagen del proceso de urbanizaciâ”œâ”‚n del tramo de antigua muralla medieval de la calle del Asalto, denominado "de los Sitios", aunque su origen es de unos cuantos siglos antes: la cerca almenada musulmana de adobe y tapial con que cerrar el arrabal surgido entre la puerta Bab al-Qiblath y la de Bâ”œأ­b al-Yahâ”œâ•‘dâ”œآ،n. Tras la conquista cristiana, esta muralla fue reforzada con ladrillo en el siglo XIV. En los siglos XVII-XVIII estos muros se convirtieron en parte del largo "paseo de las tapias" que desde el convento de San Agustâ”œآ،n circundaba casi todo el flanco sur de la ciudad, hasta la puerta del Portillo. A finales del siglo XIX este tramo fue convertido en las traseras del convento de las MM. Capuchinas, cuya entrada principal estaba en la calle de Manuela Sancho. Tras vender el terreno y trasladarse a la periferia, este espacio fue convertido en el solar de una nueva urbanizaciâ”œâ”‚n residencial. El tramo de muralla, como consecuencia de las inimaginables implicaciones de 1808-1809, fue preservado, restaurado e integrado en el conjunto. En la imagen, capturada desde el interior del gran solar, la excavaciâ”œâ”‚n de los cimientos de obra permite una visual de la estratigrafâ”œآ،a bajo estos muros, resultado de siglos de actividad constructiva. El gran vano arquitrabado, posiblemente uno de los antiguos trenques abiertos como paso a travâ”œآ®s de la muralla, serâ”œأ­ luego reutilizado como puerta de acceso a los garajes. Al fondo, los grandes bloques de la calle de Jorge Cocci.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.64933800, -0.87240400, '0101000020E610000064C91CCBBBEAEBBF6806F1811DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19144071999.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19144071999.webp', 'https://www.flickr.com/photos/zaragozaantigua/19144071999/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21317, 'Calle de Don Jaime I 1905', 'Imagen capturada en la calle de Don Jaime I y centrada en unas obras abiertas a la altura del nâ”¬â•‘ 41, que fuera antigua casa del marquâ”œآ®s de San Martâ”œآ،n, con los bajos habilitados como comerciales locales. Unos aâ”œâ–’os mâ”œأ­s tarde, el establecimiento de venta de vinos, aguardientes y licores de la derecha, esquinero con la antigua plazuela de San Martâ”œآ،n y Atarâ”œآ®s (luego de Ariâ”œâ–’o), serâ”œآ،a reconvertido en la sede del periâ”œâ”‚dico La Crâ”œâ”‚nica. Fuente visual: www.todocoleccion.net/', 1905, 1905, 1905, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65369300, -0.87815400, '0101000020E61000002D40DB6AD619ECBFE34F5436ACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40298279371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40298279371.webp', 'https://www.flickr.com/photos/zaragozaantigua/40298279371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21531, 'Don Jaime I 1921', 'Desfile procesional del partido carlista-jaimista (por Jaime de Borbâ”œâ”‚n y Borbâ”œâ”‚n-Parma, pretendiente carlista al trono de Espaâ”œâ–’a), Comuniâ”œâ”‚n Tradicionalista, incluido dentro del programa de su asamblea general celebrada en Zaragoza, durante el que se habâ”œآ،a bendecido una imagen del Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s, y ahora se la estaba trasladando en procesionaria hasta la sede del Câ”œآ،rculo Jaimista, en la calle de Espoz y Mina nâ”¬â•‘ 6. La comitiva se ha detenido para hacerse la foto a la altura, a la derecha, de la soleada plaza de Ariâ”œâ–’o. El abanderado de primer plano con alpargatas blancas, sobre el tendido tranviario compartido por las lâ”œآ،neas del Arrabal, y del Gâ”œأ­llego. Fuente visual: revista "La Hormiga de Oro".', 1921, 1921, 1921, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65376000, -0.87805000, '0101000020E6100000F0164850FC18ECBF6BB75D68AED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19174999631.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19174999631.webp', 'https://www.flickr.com/photos/zaragozaantigua/19174999631/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22284, 'San Juan y San Pedro 1965', 'Fotograma del cortometraje "La persecuciâ”œâ”‚n" (1965), de Alberto Sâ”œأ­nchez. Al fondo, portada de la desaparecida iglesia de San Juan y San Pedro, en la calle homâ”œâ”‚nima, derribada en 1969. Identificaciâ”œâ”‚n precisada gracias a la amable colaboraciâ”œâ”‚n de Josâ”œآ® Vicente Royo.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65338000, -0.87747000, '0101000020E61000006A1327F73B14ECBF24EEB1F4A1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15159755117.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15159755117.webp', 'https://www.flickr.com/photos/zaragozaantigua/15159755117/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22857, 'Plaza de Ariâ”œâ–’o aâ”œâ–’os 80', 'Plaza situada a mitad del recorrido de la calle de Don Jaime I. Estâ”œأ­ asentada sobre materiales de relleno, con posible origen de un foro romano primigenio por su situaciâ”œâ”‚n cerca del cruce del cardo con el decumano mâ”œأ­ximos. Estas caracterâ”œآ،sticas de inestabililidad propiciaron el agrietamiento de su solar, por lo que se convocâ”œâ”‚ un concurso para su remodelaciâ”œâ”‚n, ejecutado en 1990. La imagen reproduce el aspecto anterior a esta intervenciâ”œâ”‚n. Al fondo a la derecha, el palacio de los Torrero, renacentista del XVI, hoy sede del Colegio de Arquitectos. Fuente visual: www.facebook.com/photo.php?fbid=1593023434259220&set=...', 1980, 1980, 1989, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65375800, -0.87809900, '0101000020E61000004ACFF4126319ECBFCBBF9657AED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15604406220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15604406220.webp', 'https://www.flickr.com/photos/zaragozaantigua/15604406220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24239, 'Calle de Don Jaime I c.1895', 'Imagen capturada en la antigua plazuela de San Martâ”œآ،n y Atarâ”œآ®s y centrada en la comparsa de Gigantes y Cabezudos (en la escena aparecen las parejas de Gigantes formadas por Dulcinea-Don Quijote y la Duquesa-el Duque de Villahermosa, ideadas por Fâ”œآ®lix Oroz) "comparseando" por la calle de Don Jaime I, con el telâ”œâ”‚n de fondo edilicio del Gran Hotel de las Cuatro Naciones y del Universo, en el nâ”¬â•‘ 52 de esa vâ”œآ،a. Este hotel se construyâ”œâ”‚ en 1860 donde estuviera la casa del marquâ”œآ®s de Ariâ”œâ–’o, siendo derribado a su vez en 1973. El hijarano autor de la fotografâ”œآ،a era titular de la farmacia de la calle Mayor, y habâ”œآ،a desempeâ”œâ–’ado un destacado papel durante la reciente epidemia de Câ”œâ”‚lera que en 1885 habâ”œآ،a ocasionado en Zaragoza mâ”œأ­s de dos mil vâ”œآ،ctimas mortales.', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65371500, -0.87798300, '0101000020E6100000FC34EECD6F18ECBFCBF3E0EEACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48546091246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48546091246.webp', 'https://www.flickr.com/photos/zaragozaantigua/48546091246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24345, 'San Juan y San Pedro c.1942', 'AHPZ-Archivo Fotogrâ”œأ­fico Josâ”œآ® Galiay, (SF). Torre de la Iglesia de San Juan y San Pedro. Captura realizada desde el antiguo edificio del nâ”¬â•‘ 48 de la calle Don Jaime, cuyas traseras daban a la calle del Refugio, frente al modernista nâ”¬â•‘ 3 de la calle San Jorge, del que se ve un pedacito.', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65331400, -0.87740900, '0101000020E6100000FFE9060ABC13ECBF6D020CCB9FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700941137.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700941137.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700941137/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24432, 'Iglesia de San Juan y San Pedro 1966', 'Desde la altura del nâ”¬â•‘ 10 de la calle del Refugio, una instantâ”œأ­nea capturada durante el derribo de la iglesia de San Juan y San Pedro en la primavera de 1966, con detalle de uno de los operarios mirando a câ”œأ­mara justo en la medianera entre la torre mudâ”œآ®jar de la iglesia (considerada un hito artâ”œآ،stico) y el vecino edificio del nâ”¬â•‘ 2 de la calle de San Juan y San Pedro, que tambiâ”œآ®n fue derribado en ese momento para asolar el conjunto y permitir luego la construcciâ”œâ”‚n del actual edificio del nâ”¬â•‘ 8 de la calle del Refugio. Al fondo, traseras del veterano inmueble del nâ”¬â•‘ 3-5 de la calle de San Jorge.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65337800, -0.87760800, '0101000020E6100000ADA7565F5D15ECBF83F6EAE3A1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52764209260.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52764209260.webp', 'https://www.flickr.com/photos/zaragozaantigua/52764209260/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24450, 'Don Jaime I, 1912', '"La Crâ”œâ”‚nica" fue un diario zaragozano de carâ”œأ­cter regionalista, que apareciâ”œâ”‚ el 1 de octubre de 1912. Su sede estaba en la Calle Don Jaime I nâ”¬â•‘ 41. Dejâ”œâ”‚ de editarse en 1920. La imagen corresponde al dâ”œآ،a 12 de Noviembre de 1912: en la pizarra se ha escrito "Asesinato de Canalejas", entonces Presidente del Gobierno.', 1912, 1912, 1912, 'Anos 10', 'CASCO HISTâ”œأ´RICO', 41.65364000, -0.87813900, '0101000020E6100000D8F2CAF5B619ECBFC1ADBB79AAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15330662517.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15330662517.webp', 'https://www.flickr.com/photos/zaragozaantigua/15330662517/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25594, 'Taquillas Romareda 1965', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/setiembre 1965. La cola de las taquillas de los estadios de fâ”œâ•‘tbol, como el municipal de la Romareda, son escenarios donde encontrar variada fauna en pelaje y actitudes. Esta caprina estampa es bastante peculiar, pero no tanto en unos aâ”œâ–’os en que la zona de la Romareda aâ”œâ•‘n era un lugar de encuentro entre el agro y la urbe. La tranquilidad del rebaâ”œâ–’o, y del pastor, denota que no estamos en trepidante jornada de liga.', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.63614900, -0.90093200, '0101000020E6100000976F7D586FD4ECBF0A3197546DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14665033738.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14665033738.webp', 'https://www.flickr.com/photos/zaragozaantigua/14665033738/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25144, 'Palacio de Ariâ”œâ–’o 1650', '"Zaguâ”œأ­n de la casa de los Marqueses de Ariâ”œâ–’o de Zaragoza". Dibujo de Valentâ”œآ،n Carderera Solano, realizado en 1855, con una vista del ingreso al patio interior de este desaparecido palacio o casona seâ”œâ–’orial de fâ”œأ­brica renacentista, con varias ampliaciones y fases constructivas entre los siglos XVI y XVII. Estaba situado en la calle Baja de San Pedro, en la alargada y estrecha manzana entre las calles Alta de San Pedro, Mayor, y Refugio. En el siglo XIX fue reconvertido en la "Fonda Cuatro Naciones", y allâ”œآ، tuvo lugar el banquete que ofreciâ”œâ”‚ en 1843 el Ayuntamiento para celebrar la jura de la Constituciâ”œâ”‚n de 1837 por Isabel II. Mâ”œأ­s adelante, cuando se llevâ”œâ”‚ a cabo el proceso de realineaciâ”œâ”‚n y ensanche de la nueva calle de Don Jaime I, como suma de las calles Cuchillerâ”œآ،a, Virgen del Rosario, Baja de San Pedro, y San Gil, este palacio serâ”œأ­ derribado, como otras casonas, la antigua y cercana iglesia de San Pedro Apâ”œâ”‚stol, y la iglesia parroquial de Santiago el Mayor. Sobre su solar serâ”œأ­ levantado, al poco, el nuevo "Hotel Universo y Cuatro Naciones", frente a la plaza redenominada de Ariâ”œâ–’o, antigua de San Martâ”œآ،n. Fuente visual: ceres.mcu.es/', 1650, 1650, 1650, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65371700, -0.87787500, '0101000020E6100000643BDF4F8D17ECBF6CEBA7FFACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24880274002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24880274002.webp', 'https://www.flickr.com/photos/zaragozaantigua/24880274002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25664, 'Plaza de Ariâ”œâ–’o c.1969', 'Ensanche de la calle de Don Jaime que fuera plazuela de San Martâ”œآ،n y Atarâ”œآ®s, y luego plaza de Ariâ”œâ–’o, en una imagen centrada en la antigua casa del marquâ”œآ®s de San Martâ”œآ،n, aâ”œâ–’os despuâ”œآ®s derribada.', 1969, 1969, 1969, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65375800, -0.87809900, '0101000020E61000004ACFF4126319ECBFCBBF9657AED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22135854186.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22135854186.webp', 'https://www.flickr.com/photos/zaragozaantigua/22135854186/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25684, 'Albert Einstein 1923', 'En el centro, el fâ”œآ،sico Albert Einstein, posando el dâ”œآ،a de su 44 cumpleaâ”œâ–’os en un salâ”œâ”‚n del Hotel Universo y de las Cuatro Naciones, en la calle de Don Jaime I nâ”¬â•‘ 52, frente a la plaza de Ariâ”œâ–’o, el miâ”œآ®rcoles 14 de marzo de 1923. La instantâ”œأ­nea se tomâ”œâ”‚ tras una pequeâ”œâ–’a أ”أ‡آ£fiesta aragonesaأ”أ‡أک, en la que la niâ”œâ–’a que le acompaâ”œâ–’a acababa de bailar una jota. A su lado, Elsa, la esposa de Einstein. Tras ellos, de pie, el catedrâ”œأ­tico de Fâ”œآ،sica Jerâ”œâ”‚nimo Vecino Varona, el pianista Emil von Saâ”œâ•‌er (alojado en el mismo hotel) y Manuel Lorenzo Pardo, secretario de la Academia de Ciencias. Completan el cuadro los miembros de la rondalla. El câ”œآ®lebre alemâ”œأ­n se marchâ”œâ”‚ este mismo dâ”œآ،a de Zaragoza, a donde habâ”œآ،a llegado el dâ”œآ،a 12 procedente de Madrid, tras ofrecer sendas conferencias el lunes y el martes en la Facultad de Medicina y Ciencias.', 1923, 1923, 1923, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65378200, -0.87792100, '0101000020E61000007A17EFC7ED17ECBF535BEA20AFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52738829138.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52738829138.webp', 'https://www.flickr.com/photos/zaragozaantigua/52738829138/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23987, 'La Hâ”œآ،pica 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Junio 1966. Imagen de la entrega de trofeos en el transcurso de una fiesta en "La Hâ”œآ،pica". A la izquierda, la calle San Francisco de Borja.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.64036700, -0.90232200, '0101000020E610000011C30E63D2DFECBF0438BD8BF7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15533950877.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15533950877.webp', 'https://www.flickr.com/photos/zaragozaantigua/15533950877/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20940, 'Torre Nueva 1504', 'Dibujo del arquitecto Francisco â”œأ¬â”œâ–’iguez Almech recreando el que hubiera sido el original estado de la Torre Nueva de Zaragoza, desprovista del chapitel y remate que en su â”œâ•‘ltima versiâ”œâ”‚n (1746) perdurâ”œâ”‚ hasta su eliminaciâ”œâ”‚n en 1878 como paso previo al derribo culminado en 1893. La plâ”œأ­stica de este remate recuerda mâ”œأ­s a los alminares de la Saraqusta islâ”œأ­mica, que a las torres de principios del siglo XVI. A pesar de las dudas, y siguiendo las dataciones de la documentaciâ”œâ”‚n conservada del siglo XVIII, â”œأ¬â”œâ–’iguez datâ”œâ”‚ la torre en 1504. El dibujo recrea desde cierta altura la torre en su tradicional entorno de la plaza de San Felipe, con un mercadillo instalado a sus pies. Tras ella y a la derecha, la casona de los Cerdâ”œأ­n de Escatrâ”œâ”‚n con su rotundo torreâ”œâ”‚n esquinero. A la izquierda, la casa del marquâ”œآ®s de Villaverde, y la iglesia de San Felipe con su traza barroca de bastante tiempo despuâ”œآ®s.', 1504, 1504, 1504, 'Siglo XIX', 'CENTRO', 41.65476500, -0.88213500, '0101000020E6100000D105F52D733AECBF60C8EA56CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50012247372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50012247372.webp', 'https://www.flickr.com/photos/zaragozaantigua/50012247372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20968, 'La Tour penchâ”œآ®e 1832', '"La Tour penchâ”œآ®e de Saragosse". Xilografâ”œآ،a de Pharamon Blanchard coloreada a mano. Viaje pintoresco a Espaâ”œâ–’a, 1832. A los pies de la Torre Nueva, comparsa de gigantones, los precedentes de los actuales gigantes y cabezudos.', 1832, 1832, 1832, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19058875165.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19058875165.webp', 'https://www.flickr.com/photos/zaragozaantigua/19058875165/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20978, 'Torre Nueva 1858', '"Plantas, secciâ”œâ”‚n y alzado de la Torre Nueva de esta ciudad, vista por donde presenta la mayor inclinaciâ”œâ”‚n, y proyecto de reparaciâ”œâ”‚n en su parte inferior, con arreglo a lo prevenido por la Real Acacdemia de Nobles Artes de San Fernando en 18 de septiembre de 1849 mandado llevar a devido cumplimiento en Real orden de 5 de octubre del mismo aâ”œâ–’o", Josâ”œآ® Yarza y Joaquâ”œآ،n Gironza, Zaragoza, 29 de mayo de 1858. Acabada en 1512, la Torre Nueva de Zaragoza se derribâ”œâ”‚ en 1892. Fuente: AMZ.', 1858, 1858, 1858, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20421586814.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20421586814.webp', 'https://www.flickr.com/photos/zaragozaantigua/20421586814/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20997, 'Calle de Contamina 1855', 'Dibujo de Valentâ”œآ،n Carderera centrado en la monumental escalera de acceso a la antigua casa de la familia Virto de Vera en la calle de Contamina, cuando su propiedad era ya del emprendedor Joaquâ”œآ،n Marâ”œآ،n, poco antes de ser expropiada y derribada durante el radical ensanche y alineaciâ”œâ”‚n de la nueva calle de Alfonso I. Esta gran casa habilitaba un paso, denominado de Virto, que comunicaba las calles de Contamina y de la Salud, casi literalmente por donde serâ”œآ،a trazado el nuevo vial impulsado por el empecinado alcalde Antonio Candalija y Uribe. Joaquâ”œآ،n Marâ”œآ،n habâ”œآ،a comprado la casa a los duques de Villahermosa, cerrando de esta forma el traspaso del inmueble entre algunas de las mâ”œأ­s selectas sagas de la hidalguâ”œآ،a, infanzonâ”œآ،a y nobleza local (Azlor, Virto de Vera, Fuembuena-Lierta, Villahermosa). Fuente visual: Archivo Palacio Villahermosa (Pedrola), en Manuel Garcâ”œآ،a Guatas, Los â”œأ­lbumes de Pedrola. Apuntes y acuarelas de Valentâ”œآ،n Carderera en los â”œأ­lbumes del palacio de los Duques de Villahermosa de Pedrola, IFC, 2017.', 1855, 1855, 1855, 'Siglo XIX', 'CENTRO', 41.65474300, -0.88050300, '0101000020E6100000D8F4A0A0142DECBF79245E9ECED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38894108700.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38894108700.webp', 'https://www.flickr.com/photos/zaragozaantigua/38894108700/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21003, 'Torre Nueva c.1865', 'Fotografâ”œآ،a realizada por Josâ”œآ® Martâ”œآ،nez Sâ”œأ­nchez, e incorporada en 1868 al Archivo de Laurent. Fuente: Archivo Ruiz Vernacci, Fototeca del Patrimonio Histâ”œâ”‚rico (www.mcu.es/).', 1865, 1865, 1865, 'Siglo XIX', 'CENTRO', 41.65471700, -0.88217300, '0101000020E610000031410DDFC23AECBF4F9143C4CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14679984819.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14679984819.webp', 'https://www.flickr.com/photos/zaragozaantigua/14679984819/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
