INSERT INTO public.photos VALUES (21022, 'Calle Alfonso 1867', '"Proyecto de la nueva calle de Don Alfonso I y de las que afluyen a la misma", Segundo Dâ”œآ،az, Zaragoza, 3 de mayo de 1867. La apertura de la calle de Alfonso I fue la mayor operaciâ”œâ”‚n de reorganizaciâ”œâ”‚n urbanâ”œآ،stica del siglo XIX en Zaragoza. Se trataba de comunicar el Coso Alto con la plaza del Pilar en lâ”œآ،nea recta, para favorecer el comercio. En 1858 se iniciâ”œâ”‚ el debate del proceso: abrir la calle del Trenque hasta el Pilar pasando por las de Fuenclara, Montera (Candalija), Torre Nueva, Contamina, Salud (Roda, Santa Isabel), Platerâ”œآ،a (Manifestaciâ”œâ”‚n), Mayor, Concepciâ”œâ”‚n (Prudencio), Santa Marâ”œآ،a la Mayor (Santiago) y Los Navarros. Josâ”œآ® de Yarza entregâ”œâ”‚ el proyecto en 1860. Los derribos se produjeron entre noviembre de 1866 y marzo de 1867. Fuente: AMZ.', 1867, 1867, 1867, 'Siglo XIX', 'CENTRO', 41.65437800, -0.88107500, '0101000020E6100000A857CA32C431ECBF679C86A8C2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20845103658.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20845103658.webp', 'https://www.flickr.com/photos/zaragozaantigua/20845103658/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21028, 'Torre Nueva c.1860', '"Vista de Zaragoza con la Torre Nueva". Autor anâ”œâ”‚nimo, posiblemente Mariano Jâ”œâ•‘dez. Desde la torre de la iglesia parroquial de San Gil, una extraordinaria vista centrada en la superlativa Torre Nueva con su triple chapitel. A su izquierda, la barroca iglesia parroquial de San Felipe. A su derecha, inmediato, el torreâ”œâ”‚n de los Fortea, y la barroca iglesia de Santa Isabel, como propiedad de la Diputaciâ”œâ”‚n Provincial de Zaragoza, y atendida por la Hermandad de la Sangre de Cristo.', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23819277440.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23819277440.webp', 'https://www.flickr.com/photos/zaragozaantigua/23819277440/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
