INSERT INTO public.photos VALUES (21063, 'Calle de la Torre Nueva 1870', 'Instantâ”œأ­nea de la Torre Nueva sobresaliendo por encima del tramo de los nâ”œâ•‘meros pares de la calle Torre Nueva comprendido entre la calle del Ciprâ”œآ®s (desde donde se habrâ”œآ،a capturado la imagen, desde cierta altura), hasta la plaza de San Felipe (al fondo). Fuente visual: original del londinense Frank Mason Good, publicada en el libro de viajes "Spain and the spaniards", Edmondo De Amicis, ediciâ”œâ”‚n 1895. ("Espaâ”œâ–’a", viaje durante el reinado de Amadeo I de Saboya).', 1870, 1870, 1870, 'Siglo XIX', 'CENTRO', 41.65411900, -0.88124700, '0101000020E6100000EF5696E82C33ECBF9B58E02BBAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15159300578.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15159300578.webp', 'https://www.flickr.com/photos/zaragozaantigua/15159300578/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
