INSERT INTO public.photos VALUES (21079, 'Torre Nueva c.1877', 'Segunda de las imâ”œأ­genes en altura de la calle Torre Nueva, capturadas por Laurent y Câ”œآ،a desde la calle de Alfonso I, realizada despuâ”œآ®s que la anterior, y aprovechando la anchura de la calle Torre Nueva para conseguir la mâ”œأ­xima visual vertical de cuerpo entero posible. El reloj lleva la fecha de fabricaciâ”œâ”‚n de "1827", y seâ”œâ–’ala las 19.05 horas. Fuente visual: Jean Laurent y Câ”œآ،a, Archivo Ruiz Vernacci (Fototeca del Patrimonio Histâ”œâ”‚rico, www.mcu.es/)', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22639481339.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22639481339.webp', 'https://www.flickr.com/photos/zaragozaantigua/22639481339/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
