INSERT INTO public.photos VALUES (21090, 'Torre Nueva c.1877', 'Grabado basado en una referencial toma fotogrâ”œأ­fica realizada por J. Laurent y C.â”¬آ¬ desde la altura de la calle Torrenueva y centrada en la Torre Nueva emergiendo de la plaza de San Felipe, en un encuadre que la centra inclinada entre la torrecilla de la iglesia de San Felipe, la antigua Casa de Argillo, la torre de la Iglesia de San Pablo y el Torreâ”œâ”‚n de los Cerdâ”œأ­n de Escatrâ”œâ”‚n. Fue publicado en 1891 en La Ilustraciâ”œâ”‚n espaâ”œâ–’ola y americana, cuando comenzaban a arreciar las voces de quienes impulsaban su derribo "para evitar que se cayera" (que no lo hubiera hecho nunca, si le hubieran dado algo de tiempo), si bien la foto era bastante anterior.', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65473300, -0.88202800, '0101000020E61000005000C5C89239ECBF554E7B4ACED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52420058939.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52420058939.webp', 'https://www.flickr.com/photos/zaragozaantigua/52420058939/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
