INSERT INTO public.photos VALUES (21131, 'Torre Nueva 1889', 'Imagen capturada desde cierta altura en la calle de Monterde y centrada en la referencial Torre Nueva (ya desmochada de su triple chapitel barroco) de la plaza de San Felipe, flanqueada por la iglesia homâ”œâ”‚nima, la casa del marquâ”œآ®s de Villaverde, y la casa de los Cerdâ”œأ­n de Escatrâ”œâ”‚n.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65472200, -0.88213500, '0101000020E6100000D105F52D733AECBF61FC34EECDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42455047004.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42455047004.webp', 'https://www.flickr.com/photos/zaragozaantigua/42455047004/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
